#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, S;
        scanf("%d %d", &N, &S);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int count = 0;
        for (int K = 0; K <= N; K++) {
            int sum = 0;
            for (int i = 0; i < N; i++) {
                int left = (i - K < 0) ? 0 : i - K;
                int right = (i + K >= N) ? N - 1 : i + K;
                int rank = 0;
                for (int j = left; j <= right; j++) {
                    if (A[j] <= A[i]) {
                        rank++;
                    }
                }
                sum += rank;
            }
            if (sum <= S) {
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

